var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ouch!","TWN":"啊呀！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FINGER_FLICK"},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"귀신 같은 소리 하네. 하여간, 잠시도 한눈을 팔 수가 없다니까.","JPN":"幽霊だなんてよく言うよ。ったく、少しも目が離せないんだから。","ENG":"No, I'm not a ghost. Geez, I knew I should have kept an eye on you two.","TWN":"鬼叫什麼，妳們這樣讓我怎麼放心。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아프다고...... 머리 좀 그만 때려, 라우라.","JPN":"痛いってば……頭を叩くのはやめてよ、ラウラ。","ENG":"Ow... That hurts... Stop hitting me on the head, Laura.","TWN":"好疼啊……別打我的頭，蘿拉。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"대체 여긴 어떻게 들어온 거야? 낙오되지 않게 바짝 쫓아오라는 말은 벌써 잊어버렸어?","JPN":"いったいここにはどうやって入ったんだ？　はぐれないように、しっかりついてこいと言っただろ？","ENG":"How did you even end up here? I told you to keep up so you won't get left behind, didn't I?","TWN":"妳們是怎麼進來的？我不是說過一定要跟緊我，不要掉隊嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아무리 우리 관리하에 있다고 해도 여긴 이면세계야.","JPN":"妾たちの管理下にあるとはいえ、ここは裏世界だ。","ENG":"Although this place may be under our management, it's still the Counterside.","TWN":"即使這裡是我們的管轄範圍，但畢竟是異界。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"쉽사리 방심했다간 어떤 일을 당할지 모른다고.","JPN":"油断したらどんな目に遭うかわからない。","ENG":"There's no telling what will happen if you let down your guard.","TWN":"一不小心就可能會出事。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나, 나도 그 정도는 알고 있어! 하지만 신입이......","JPN":"わ、私だってそのくらいわかってる！　でも新入りが……","ENG":"I-I know! But the newbie here...","TWN":"我、我也知道！不過新人她……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"신입이?","JPN":"新入りが？","ENG":"Newbie?","TWN":"新人？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"여긴...... 어디예요? 이면세계에 있다는 유적 같은 건가요?","JPN":"ここは……どこですか？　裏世界の遺跡みたいなものでしょうか？","ENG":"Where... are we? Is this some kind of ruin, the type they say can be found in the Counterside?","TWN":"這裡……是哪裡？是異界裡的遺跡嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여긴 발푸르기스 성이야.","JPN":"ここはヴァルプルギス城だ。","ENG":"This is Walpurgis Castle.","TWN":"這裡是魔女之夜城。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스 성?","JPN":"ヴァルプルギス城？","ENG":"Walpurgis Castle?","TWN":"魔女之夜城？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......그리고 출입 금지구역이지.","JPN":"……そして、立入禁止区域だ。","ENG":"And it's off-limits.","TWN":"……而且是禁止出入的區域。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"관심 가져 봐야 너희들에게 좋을 것 하나 없으니까 잊어버려.","JPN":"興味を持ったところで得することは何もないから忘れてしまえ。","ENG":"Just forget about this place. You have nothing to gain from getting nosy about it.","TWN":"不要多問，知道了對你們沒什麼好處，還是忘掉吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"거 참 말 많네. 오늘 갓 들어온 견습이 왜 이리 귀찮게 굴어?","JPN":"ったくうるさいな。今日入った見習いがどこまで面倒をかければ気が済むんだ？","ENG":"Enough with the buts already! You just got here today, dang it!","TWN":"沒完沒了了，剛來的見習哪來那麼多問題？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"더 이상 캐묻지 마. 다 이유가 있어서 금지 구역으로 정해 둔 거니까.","JPN":"これ以上聞き出そうとするな。すべて理由があって禁止区域にしたんだから。","ENG":"When I say it's off-limits, there's a good reason for it. So stop asking.","TWN":"別好奇了，被定為禁區都是有原因的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"계속 물어 보면 하루 종일 재채기가 나오는 저주를 걸어 버리겠어.","JPN":"しつこく聞いてくるなら、一日中くしゃみが止まらない呪いをかけるぞ。","ENG":"If you keep asking, I'll curse you so you'll sneeze all day.","TWN":"再問我就下詛咒，讓你們整天都打噴嚏。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"쪼, 쪼잔해......","JPN":"ひ、ひどい……","ENG":"Th-that's not fair...","TWN":"小、小氣鬼……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"섭섭하겠지만 나도 이번에는 라우라와 같은 생각이야.","JPN":"残念だろうけど、今回ばかりは私もラウラと同じ考えよ。","ENG":"I know you're disappointed, but I'm with Laura on this one.","TWN":"很遺憾，但這次我和蘿拉的想法一樣。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"언젠가 정식 마녀가 되면 싫어도 알아야 될 테니까, 지금은 그냥 잊어 버리렴.","JPN":"いつか正式な魔女になったら嫌でもわかるようになるから、今は忘れなさい。","ENG":"You'll have to learn about this place when you become a full-fledged witch anyway, even if you don't want to. So forget about it for now.","TWN":"等妳們成為正式魔女後，即使不想知道也會知道。所以現在還是忘了比較好。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네...... 알겠어요.","JPN":"はい……わかりました。","ENG":"Okay... Understood.","TWN":"好……知道了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"좋아. 그럼 돌아가자.","JPN":"よし。戻りましょうか。","ENG":"All right, let's go back then.","TWN":"好了，我們回去吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"뭐, 뭐죠? 이 진동은?","JPN":"こ、この揺れは何ですか？　","ENG":"W-what was that rumbling?","TWN":"這？這個震動是怎麼回事？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......에블린.","JPN":"……エヴリン。","ENG":"Evelyn.","TWN":"……伊芙琳。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"알고 있어. 하지만 이상하네. 아직 날짜가 이른데.","JPN":"わかってる。でもおかしいわね。まだ早いはずなのに。","ENG":"Yeah, I know. But that's odd. It's too soon.","TWN":"我知道。可是奇怪，日子還沒到啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"글쎄, 이 바보들이 돌아다니다가 뭔가 건드렸을 수도 있지.","JPN":"まあ、このバカどもが歩き回ってるうちに何かに触れたのかもしれないな。","ENG":"Maybe these fools tripped something while they were wandering around.","TWN":"也許這兩個傻瓜在溜達的時候碰到什麼東西了。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이유는 나중에 생각하자. 지금은 눈앞에 닥친 일부터 해결해야 돼.","JPN":"理由はあとで考えよう。今は目先のことから解決しないと。","ENG":"We can figure out the reason later. For now, we have to deal with the situation at hand.","TWN":"這個以後再想，現在得先解決眼前的事。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"무, 무슨 일인데요?","JPN":"な、何事なの？","ENG":"W-what's going on?","TWN":"發、發生了什麼事？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"<color=#ffd34c>인형</color>이 밖으로 빠져 나가려는 거야.","JPN":"<color=#ffd34c>人形</color>が外に出ていこうとしている。","ENG":"The <color=#ffd34c>puppets</color> are trying to escape.","TWN":"是<color=#ffd34c>木偶</color>想跑出來。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형......?","JPN":"人形……？","ENG":"Puppets?","TWN":"木偶……？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"발푸르기스 성 깊은 곳에 묶여 있는 강력한 침식체들이지.","JPN":"ヴァルプルギス城の奥深い所に縛られている強力な侵食体のことだ。","ENG":"They are powerful C.O.s fettered down deep in the Walpurgis Castle.","TWN":"是被綁在魔女之夜城深處的強大侵蝕體。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"주기적으로 성에서 도망치려 해서 나와 에블린이 따로 처리하고 있어.","JPN":"周期的に城から逃げ出そうとするから、妾とエヴリンの二人で管理していたんだが。","ENG":"They try to escape the castle on a regular basis, so Evelyn and I've been managing them separately.","TWN":"每隔一段時間它們就會試圖從城裡逃出來，需要伊芙琳單獨處理。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하지만 오늘은...... 뭔가 예외가 발생한 것 같네.","JPN":"でも今日は……何か例外が発生したようだ。","ENG":"But today seems to be some kind of an exception.","TWN":"但今天……好像出了點意外。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"강한 침식체? 그거 좋지!","JPN":"強い侵食体？　なら大歓迎よ！","ENG":"Powerful C.O.s? That's great!","TWN":"強大的侵蝕體？太好了！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이 잉그리드 님의 힘을 제대로 보여줄 기회라고!","JPN":"このイングリッド様の力を見せつけるチャンスでしょ！","ENG":"It's finally time to show them my true power!","TWN":"剛好趁這個機會，我可以好好施展一番！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"방금 흔들리는 걸 봐선 이번엔 제 3종 침식체일 텐데? 상대할 자신 있어?","JPN":"さっきの揺れの規模だと今回は第3種侵食体のはずだが？　相手する自信はあるか？","ENG":"These tremors suggest that they're at least Category 3. You sure you're up for this?","TWN":"看剛剛的搖晃程度，應該是3類侵蝕體，妳能應對嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"제 3종? 지, 진짜야......?","JPN":"第3種？　ほ、本当……？","ENG":"C-Category 3? For real?","TWN":"3類？真，真的嗎……？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"엄청 위험하잖아요! 도망쳐야 하는 거 아니에요?","JPN":"危険すぎます！　逃げたほうがいいのでは？","ENG":"That's too dangerous! Shouldn't we get out of here?","TWN":"那豈不是很危險！我們是不是該趕緊逃走啊？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"분위기 파악이 빨라서 좋네.","JPN":"状況把握が早くていいな。","ENG":"I like the way you think.","TWN":"還挺有自覺的啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번엔 정말 장난이 아니니까 둘 다 다치지 않게 물러나 있으라고.","JPN":"今回は本当に危ないから、二人とも怪我しないように下がっていろ。","ENG":"Both of you stand back. It's no joke this time.","TWN":"這次可不是開玩笑的，妳們倆退後，別受傷了。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린!","JPN":"エヴリン！","ENG":"Evelyn!","TWN":"伊芙琳！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"응, 알고 있어.","JPN":"うん、わかってる。","ENG":"Yeah, I know.","TWN":"嗯，我知道。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"녀석이 성을 빠져나가지 못하게 내가 결계를 만들게.","JPN":"やつが城から抜け出せないように、私が結界を張るわ。","ENG":"I'll set up a barrier so they can't leave the castle.","TWN":"我佈個結界，讓它無法逃出城。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"좋아...... 온다!","JPN":"よし……来るぞ！","ENG":"Alright... Here they come!","TWN":"好……來了！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};